      <rect x={tip.x - tip.text.length * 3.5 - 6} y={tip.y - 24} width={tip.text.length * 7 + 12} height={20} rx={4} fill="var(--color-bg, #111)" stroke="var(--color-text-muted, #666)" strokeWidth="0.5" opacity="0.95" />
