function NestedComponentList({ components, onChange }: { components: ComponentData[]; onChange: (comps: ComponentData[]) => void }) {
  const [addOpen, setAddOpen] = React.useState(false);
  return (
    <div className="pe-nested">
      {components.map((c, i) => (
        <div key={i} className="pe-component pe-component-nested">
          <div className="pe-component-header">
            <span className="pe-component-type">{c.type}</span>
            <div className="pe-component-actions">
              {i > 0 && <button className="pe-move-btn" onClick={() => { const n = [...components]; [n[i-1], n[i]] = [n[i], n[i-1]]; onChange(n); }}>&uarr;</button>}
              {i < components.length - 1 && <button className="pe-move-btn" onClick={() => { const n = [...components]; [n[i], n[i+1]] = [n[i+1], n[i]]; onChange(n); }}>&darr;</button>}
              <button className="pe-remove-btn" onClick={() => onChange(components.filter((_, j) => j !== i))}>&times;</button>
            </div>
          </div>
          <div className="pe-component-body">
            <ComponentFieldEditor comp={c} onChange={(updated) => { const n = [...components]; n[i] = updated; onChange(n); }} />
          </div>
        </div>
      ))}
      <div className="pe-add-wrap">
        <button className="pe-list-add" onClick={() => setAddOpen(!addOpen)}>+ Add block</button>
        {addOpen && <div className="pe-add-menu">{EDITOR_TYPES.map(t => <button key={t.type} className="pe-add-option" onClick={() => { onChange([...components, newEditorComponent(t.type)]); setAddOpen(false); }}><span className="pe-add-option-icon">{t.icon}</span><span className="pe-add-option-label">{t.label}</span></button>)}</div>}
      </div>
    </div>
  );
}

function KazamComponentEditor({ comp, index, onChange, onRemove, onMove, isFirst, isLast }: {
  comp: ComponentData; index: number;
  onChange: (index: number, data: ComponentData) => void;
  onRemove: (index: number) => void;
  onMove: (index: number, direction: -1 | 1) => void;
  isFirst: boolean; isLast: boolean;
}) {
  const label = EDITOR_TYPES.find(t => t.type === comp.type)?.label || comp.type;
  return (
    <div className="pe-component">
      <div className="pe-component-header">
        <span className="pe-component-type">{label}</span>
        <div className="pe-component-actions">
          {!isFirst && <button className="pe-move-btn" onClick={() => onMove(index, -1)} title="Move up">&uarr;</button>}
          {!isLast && <button className="pe-move-btn" onClick={() => onMove(index, 1)} title="Move down">&darr;</button>}
          <button className="pe-remove-btn" onClick={() => onRemove(index)}>&times;</button>
        </div>
      </div>
      <div className="pe-component-body">
        <ComponentFieldEditor comp={comp} onChange={(c) => onChange(index, c)} />
      </div>
    </div>
  );
}

export function PageEditor({ page, onChange }: { page: PageData; onChange: (page: PageData) => void }) {
  const [addMenuOpen, setAddMenuOpen] = React.useState(false);
  const comps = page.components || [];

  const updateComponent = React.useCallback((index: number, data: ComponentData) => {
    const next = [...comps]; next[index] = data;
    onChange({ ...page, components: next });
  }, [page, comps, onChange]);

  const removeComponent = React.useCallback((index: number) => {
    onChange({ ...page, components: comps.filter((_, i) => i !== index) });
  }, [page, comps, onChange]);

  const moveComponent = React.useCallback((index: number, direction: -1 | 1) => {
    const next = [...comps];
    const target = index + direction;
    if (target < 0 || target >= next.length) return;
    [next[index], next[target]] = [next[target], next[index]];
    onChange({ ...page, components: next });
  }, [page, comps, onChange]);

  const addComponent = React.useCallback((type: string) => {
    onChange({ ...page, components: [...comps, newEditorComponent(type)] });
    setAddMenuOpen(false);
  }, [page, comps, onChange]);

  return (
    <div className="pe-root">
      <div className="pe-meta">
        <input className="pe-input pe-input-title" placeholder="Untitled" value={page.title || ""} onChange={(e) => onChange({ ...page, title: e.target.value })} />
        <input className="pe-input pe-input-subtitle" placeholder="Add a subtitle..." value={page.subtitle || ""} onChange={(e) => onChange({ ...page, subtitle: e.target.value || undefined })} />
      </div>
      <div className="pe-components">
        {comps.map((comp, i) => (
          <KazamComponentEditor key={i} comp={comp} index={i} onChange={updateComponent} onRemove={removeComponent} onMove={moveComponent} isFirst={i === 0} isLast={i === comps.length - 1} />
        ))}
      </div>
      <div className="pe-add-wrap">
        <button className="pe-add-btn" onClick={() => setAddMenuOpen(!addMenuOpen)}>
          {comps.length === 0 ? "Click to add your first block..." : "+ Add block"}
        </button>
        {addMenuOpen && (
          <div className="pe-add-menu">
            {EDITOR_TYPES.map(t => (
              <button key={t.type} className="pe-add-option" onClick={() => addComponent(t.type)}>
                <span className="pe-add-option-icon">{t.icon}</span>
                <span><span className="pe-add-option-label">{t.label}</span></span>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export { KazamComponentEditor, ComponentFieldEditor, NestedComponentList, EDITOR_TYPES, newEditorComponent };
